import React, { useEffect, useState } from 'react';
import { useAuth } from '../context/AuthContext';
import { 
  listenAuction, startAuction, closeAuction, 
  listenPlayers, addPlayer, deletePlayer, 
  resetAllWins, clearAllRecords 
} from '../firebase/services';
import toast from 'react-hot-toast';

export default function AdminDashboard() {
  const { logout } = useAuth();
  const [auction, setAuction] = useState(null);
  const [players, setPlayers] = useState([]);
  const [settings, setSettings] = useState({ monthlyAmount: 5000, totalPlayers: 10 });
  const [newPlayer, setNewPlayer] = useState({ name: '', email: '', password: '' });
  const [loading, setLoading] = useState(false);

  useEffect(() => {
    const unsubs = [
      listenAuction(setAuction),
      listenPlayers((data) => {
        // FILTER: This ensures the Admin (you) is NOT in the list
        const onlyFamily = data.filter(p => p.isAdmin !== true);
        setPlayers(onlyFamily);
      })
    ];
    return () => unsubs.forEach(u => u());
  }, []);

  const handleAddPlayer = async (e) => {
    e.preventDefault();
    setLoading(true);
    try {
      await addPlayer(newPlayer.email, newPlayer.password, newPlayer.name);
      toast.success("Family member added!");
      setNewPlayer({ name: '', email: '', password: '' });
    } catch (err) { toast.error(err.message); }
    finally { setLoading(false); }
  };

  return (
    <div className="page-wide" style={{ padding: '20px', maxWidth: '1000px', margin: '0 auto' }}>

      {/* 1. TOP NAVBAR */}
      <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '30px' }}>
        <h1 style={{ color: 'var(--gold)', margin: 0 }}>👑 Admin Control</h1>
        <button className="btn btn-danger btn-sm" onClick={logout}>Logout</button>
      </div>

      {/* 2. ADD PLAYER SECTION */}
      <div className="card" style={{ marginBottom: '30px', padding: '20px' }}>
        <h3 style={{ marginBottom: '15px' }}>➕ Add New Family Member</h3>
        <form onSubmit={handleAddPlayer} style={{ display: 'flex', flexWrap: 'wrap', gap: '10px' }}>
          <input type="text" className="form-input" placeholder="Name" required value={newPlayer.name} onChange={e => setNewPlayer({...newPlayer, name: e.target.value})} style={{ flex: 1, minWidth: '150px' }} />
          <input type="email" className="form-input" placeholder="Email" required value={newPlayer.email} onChange={e => setNewPlayer({...newPlayer, email: e.target.value})} style={{ flex: 1, minWidth: '150px' }} />
          <input type="password" className="form-input" placeholder="Password" required value={newPlayer.password} onChange={e => setNewPlayer({...newPlayer, password: e.target.value})} style={{ flex: 1, minWidth: '150px' }} />
          <button className="btn btn-primary" disabled={loading} style={{ padding: '10px 30px' }}>
            {loading ? "Adding..." : "Add"}
          </button>
        </form>
      </div>

      {/* 3. LIVE AUCTION CONTROL */}
      <div className="card" style={{ marginBottom: '30px', padding: '40px 20px', textAlign: 'center', backgroundColor: 'rgba(255, 215, 0, 0.05)' }}>
        {auction?.active ? (
          <div>
            <span className="badge badge-green">LIVE NOW</span>
            <h1 style={{ fontSize: '4rem', color: 'var(--gold)', margin: '15px 0' }}>
              ₹{auction.currentBid?.toLocaleString('en-IN') || '0'}
            </h1>
            <p style={{ fontSize: '1.2rem', marginBottom: '20px' }}>Current Leader: <b>{auction.currentBidderName || "No bids yet"}</b></p>
            <button className="btn btn-danger" style={{ padding: '15px 50px', fontSize: '1.1rem' }} onClick={() => closeAuction(auction)}>
              🛑 END AUCTION & PICK WINNER
            </button>
          </div>
        ) : (
          <div>
            <h3 style={{ marginBottom: '20px' }}>Next Monthly Auction</h3>
            <div style={{ display: 'flex', justifyContent: 'center', alignItems: 'flex-end', gap: '15px' }}>
              <div style={{ textAlign: 'left' }}>
                <label className="form-label">BC Amount (₹)</label>
                <input type="number" className="form-input" value={settings.monthlyAmount} onChange={e => setSettings({...settings, monthlyAmount: Number(e.target.value)})} style={{ width: '150px' }} />
              </div>
              <button className="btn btn-primary" style={{ padding: '12px 40px' }} onClick={() => startAuction(settings)}>
                🚀 START AUCTION
              </button>
            </div>
          </div>
        )}
      </div>

      {/* 4. PLAYER LISTING */}
      <div className="card" style={{ padding: '20px' }}>
        <h3 style={{ marginBottom: '20px' }}>👥 Family Members ({players.length})</h3>
        {players.length > 0 ? (
          <table className="records-table" style={{ width: '100%', borderCollapse: 'collapse' }}>
            <thead>
              <tr style={{ textAlign: 'left', borderBottom: '1px solid #333' }}>
                <th style={{ padding: '12px' }}>Name</th>
                <th style={{ padding: '12px' }}>Status</th>
                <th style={{ padding: '12px' }}>Action</th>
              </tr>
            </thead>
            <tbody>
              {players.map(p => (
                <tr key={p.id} style={{ borderBottom: '1px solid #222' }}>
                  <td style={{ padding: '12px' }}>
                    <b>{p.name}</b><br/>
                    <small style={{ color: '#888' }}>{p.email}</small>
                  </td>
                  <td style={{ padding: '12px' }}>
                    {p.hasWon ? <span className="badge badge-green">Won ({p.wonMonth})</span> : <span className="badge badge-muted">Eligible</span>}
                  </td>
                  <td style={{ padding: '12px' }}>
                    <button className="btn btn-danger btn-sm" onClick={() => deletePlayer(p.id)}>🗑️ Remove</button>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        ) : (
          <p style={{ textAlign: 'center', color: '#888', padding: '20px' }}>No family members found. Add some above!</p>
        )}
      </div>

      {/* 5. FOOTER RESET */}
      <div style={{ marginTop: '50px', textAlign: 'center', opacity: 0.6 }}>
        <button className="btn btn-ghost" style={{ fontSize: '0.8rem', color: '#ff4d4d' }} onClick={() => {
          if(window.confirm("Wipe all data?")) { clearAllRecords(); resetAllWins(); }
        }}>
          System Reset (Cycle Complete)
        </button>
      </div>

    </div>
  );
}
